import heapq
from collections import defaultdict

def solve(edges: list[list[int]], online: list[bool], k: int) -> int:
    n = len(online)
    graph = defaultdict(list)
    for u, v, cost in edges:
        graph[u].append((v, cost))

    # We'll use a max-heap (by pushing negative values) to track the current min edge cost in the path
    # Each heap element is a tuple: (-current_min_cost, total_cost, current_node)
    heap = []
    # The initial path starts at node 0 with no edges, but we need to handle the first edge
    # So we push edges from node 0 with their cost as the initial min
    for v, cost in graph[0]:
        if online[v] or v == n - 1:
            if cost <= k:
                heapq.heappush(heap, (-cost, cost, v))

    max_score = -1

    while heap:
        neg_min_cost, total_cost, u = heapq.heappop(heap)
        current_min = -neg_min_cost

        if u == n - 1:
            if current_min > max_score:
                max_score = current_min
            continue

        for v, cost in graph[u]:
            if not online[v] and v != n - 1:
                continue
            new_total = total_cost + cost
            if new_total > k:
                continue
            new_min = min(current_min, cost)
            heapq.heappush(heap, (-new_min, new_total, v))

    return max_score if max_score != -1 else -1
